+++ b/ghost/core/core/server/services/comments/comments-service.js
@@ -263,7 +263,7 @@
         const {page, limit} = options;
         const result = await this.models.CommentLike.findPage({
             filter: `comment_id:'${commentId}'`,
-            withRelated: [],
+            withRelated: ['member'],
             order: 'created_at desc',
             page,
             limit
"
  },
  {
    "file": "ghost/core/core/server/services/comments/comments-controller.js",
    "line": 370,
    "severity": "critical",
    "description": "The commentId is extracted from frame.data.id, but according to the endpoint definition in comment-likes.js, 'id' is declared in the options array (query parameters), not in the request body. This should use frame.options.id. Using frame.data.id will always pass undefined as the commentId, causing the endpoint to fail. The similar method getCommentReporters correctly uses frame.options.id.",
    "fix_patch": "--- a/ghost/core/core/server/services/comments/comments-controller.js
+++ b/ghost/core/core/server/services/comments/comments-controller.js
@@ -367,7 +367,7 @@

     /**
      * Get likes for a specific comment (admin only)
      * @param {Frame} frame
      */
     async getCommentLikes(frame) {
-        const commentId = frame.data.id;
+        const commentId = frame.options.id;
         return await this.service.getCommentLikes(commentId, {
             page: frame.options.page,
             limit: frame.options.limit
"
  },
  {
    "file": "ghost/core/core/server/api/endpoints/comment-likes.js",
    "line": 8,
    "severity": "medium",
    "description": "The browse endpoint is missing cache control headers. Read-only admin API endpoints should include explicit Cache-Control headers to prevent unwanted caching. This is a compliance violation with Ghost's API conventions for proper HTTP cache behavior.",
    "fix_patch": "--- a/ghost/core/core/server/api/endpoints/comment-likes.js
+++ b/ghost/core/core/server/api/endpoints/comment-likes.js
@@ -21,6 +21,9 @@
         },
         // Use comment permissions - browsing likes is part of comment moderation
         permissions: {
             docName: 'comments'
         },
+        headers: {
+            'Cache-Control': 'private, no-cache'
+        },
         query(frame) {
             return commentsService.controller.getCommentLikes(frame);
         }
"
  }
]

